dtsPropsFor.CensoredImage:
/** Image to blur until the viewer opts in. Static import or URL. */
src: string;
/** Alternative text, read out whether or not the image is revealed. */
alt: string;
/** Caption rendered under the image. */
caption?: string;

dtsPropsFor.OuraDashboard:
/**
 * Metric families to render. Must be an ARRAY — a bare string is ignored
 * and every family is fetched. `null` (the default) also renders all.
 */
subset?: Array<'activity' | 'readiness' | 'sleep' | 'sleep_detail' | 'stress' | 'spo2' | 'resilience' | 'heart_rate' | 'sleep_time' | 'sessions' | 'workout' | 'personal_info' | 'vo2_max' | 'cardio_age'> | null;
/**
 * Masonry columns — a fixed count, or one per breakpoint.
 * Default `{ xs: 1, sm: 2, lg: 3 }`.
 */
columns?: number | { xs?: number; sm?: number; md?: number; lg?: number; xl?: number };
/** CSS height applied to each chart tile. Default `'280px'`. */
chartHeight?: string;
/** CSS width applied to each chart tile. Default `'100%'`. */
chartWidth?: string;
/** Show the dashboard heading. Default `true`. */
showHeader?: boolean;
/** Tighten tile padding for dense layouts. Default `false`. */
compact?: boolean;

dtsPropsFor.ActivityChart:
/** One entry per day. Renders an empty state when omitted or empty. */
data?: Array<{
  /** ISO date, e.g. `'2026-07-21'`. */
  day: string;
  /** Step count for that day. */
  steps: number;
}>;

dtsPropsFor.ReadinessChart:
/** One entry per day. Renders an empty state when omitted or empty. */
data?: Array<{
  /** ISO date, e.g. `'2026-07-21'`. */
  day: string;
  /** Readiness score. The y-axis is fixed to the 40–100 range. */
  score: number;
}>;

dtsPropsFor.SleepChart:
/** One entry per day. Renders an empty state when omitted or empty. */
data?: Array<{
  /** ISO date, e.g. `'2026-07-21'`. */
  day: string;
  /** Per-contributor sleep scores, each 1–100. */
  contributors?: {
    deep_sleep?: number;
    rem_sleep?: number;
    efficiency?: number;
    latency?: number;
    restfulness?: number;
    timing?: number;
    total_sleep?: number;
  };
}>;

dtsPropsFor.StressChart:
/** One entry per day. Renders a labelled empty state when omitted or empty. */
data?: Array<{
  /** ISO date, e.g. `'2026-07-21'`. */
  day: string;
  /** Seconds spent in high stress that day. */
  stress_high?: number;
  /** Seconds spent in recovery that day. Stacked under stress_high. */
  recovery_high?: number;
}>;

dtsPropsFor.SpO2Chart:
/** One entry per day. Renders a labelled empty state when omitted or empty. */
data?: Array<{
  /** ISO date, e.g. `'2026-07-21'`. */
  day: string;
  /** Blood-oxygen readings. Only `average` is plotted. */
  spo2_percentage?: { average?: number };
}>;

dtsPropsFor.WorkoutChart:
/** One entry per day. Renders a labelled empty state when omitted or empty. */
data?: Array<{
  /** ISO date, e.g. `'2026-07-21'`. */
  day: string;
  /** Calories burned in that day's workouts. */
  calories?: number;
}>;

dtsPropsFor.ResilienceChart:
/** One entry per day. Renders a labelled empty state when omitted or empty. */
data?: Array<{
  /** ISO date, e.g. `'2026-07-21'`. */
  day: string;
  /** Two plotted lines, each 0-100. */
  contributors?: { sleep_recovery?: number; stress?: number };
}>;

dtsPropsFor.CardioAgeChart:
/** One entry per day. Renders a labelled empty state when omitted or empty. */
data?: Array<{
  /** ISO date, e.g. `'2026-07-21'`. */
  day: string;
  /** Estimated vascular age in years. */
  vascular_age?: number;
}>;

dtsPropsFor.VO2MaxChart:
/** One entry per day. Renders a labelled empty state when omitted or empty. */
data?: Array<{
  /** ISO date, e.g. `'2026-07-21'`. */
  day: string;
  /** Estimated VO2 max, ml/kg/min. */
  vo2_max?: number;
}>;

dtsPropsFor.SleepDetailChart:
/** One entry per day. Renders a labelled empty state when omitted or empty. */
data?: Array<{
  /** ISO date, e.g. `'2026-07-21'`. */
  day: string;
  /** Durations in SECONDS, not minutes. */
  total_sleep_duration?: number;
  deep_sleep_duration?: number;
  light_sleep_duration?: number;
  rem_sleep_duration?: number;
  awake_time?: number;
}>;

dtsPropsFor.HeartRateChart:
/** Individual readings, not daily aggregates. Empty state when omitted. */
data?: Array<{
  /** ISO timestamp of the reading. */
  timestamp: string;
  /** Beats per minute. */
  bpm: number;
}>;
/** Explicit [start, end] time domain. Derived from the data when omitted. */
xDomain?: [Date | number, Date | number];

dtsPropsFor.PersonalInfoCard:
/** Singleton payload; an array is accepted and its first entry used. */
data?: {
  age?: number;
  /** Kilograms — the unit is appended for you. */
  weight?: number;
  /** Metres — the unit is appended for you. */
  height?: number;
  biological_sex?: string;
  email?: string;
} | Array<{ age?: number; weight?: number; height?: number; biological_sex?: string; email?: string }> | null;

dtsPropsFor.SleepTimeCard:
/** REQUIRED — this card maps over `data` with no guard and throws if it is
 *  omitted. Pass `[]` for the empty state. */
data: Array<{
  day?: string;
  status?: string;
  /** Offsets in SECONDS; rendered as whole hours. */
  optimal_bedtime?: { start_offset?: number; end_offset?: number };
  recommendation?: string;
}>;

dtsPropsFor.RestModeCard:
/** REQUIRED — mapped with no guard; pass `[]` for the empty state. */
data: Array<{
  start_day?: string;
  /** Omit or null to render as "Ongoing". */
  end_day?: string | null;
  /** REQUIRED per entry — mapped with no guard. */
  episodes: Array<{ tags: string[] }>;
}>;

dtsPropsFor.SimpleListCard:
/** REQUIRED — mapped with no guard; pass `[]` for the empty state. */
data: unknown[];
/** Heading shown at the top of the card. */
title?: string;
/** Renders one entry. Called for every item in `data`. */
renderItem: (item: unknown) => React.ReactNode;
